class Solution:
    def reverseWords(self, s):
        words = []
        cur = []
        for ch in s:
            if ch == ' ':
                if cur:
                    words.append(''.join(cur))
                    cur = []
            else:
                cur.append(ch)
        if cur:
            words.append(''.join(cur))
        return ' '.join(reversed(words))

